INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (34647,'com3','김형식','','2024년 꿈나무 체육대회 참가(2024.05.04)','계절을 무색하게 만드는 더위가 기승을 부린 날.

<div>서울특별시 주관, 서울시 아동복지협회 주최로 한양대학교 대운동장에서</div>
<div>2024년 아동복지협회 꿈나무 체육대회가 열려 참여했습니다.</div>
<div><br /></div>
<div>시설 연합으로 4개 팀으로 나눠(남산원은 방글핑!!)</div>
<div>볼풀공던지기, 100m 달리기, 단체줄넘기, 신발 양궁, 훌라후프 통과하기 등</div>
<div>진행된 경기에 아동들이 골고루 참여해 역량을 발휘했습니다.</div>
<div>연합한 시설들과 시너지가 좋아 종합우승까지 거머쥐었습니다~~ ^0^</div>
<div>종합우승에 장남매(장*울, 장*아)의 활약이 빛났는데</div>
<div>결국 동생 *아가 MVP를 탔습니다!!</div>
<div><br /></div>
<div>연합으로 함께 수고한 선덕원, 신명아이마루, 에델마을과&nbsp;</div>
<div>수고해 주신 모든 분들께 감사드립니다!!</div>
<div>가정의 달 5월 아동들이 소외감 느끼지 않고,&nbsp;</div>
<div>더 행복한 시간 보내도록 지원하겠습니다.&nbsp;</div>          </td>
        </tr>',526,1714748400,'', '', '', '', '', '');
