INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32820,'com3','이재웅','capwoong79@gmail.com','2023년 여름캠프 1일차 (2023.08.01.)','<table border="0" cellspacing="0" cellpadding="0" width="100%" style="font-size: 12px; color: #847f74; line-height: 19.2px; font-family: verdana"><colgroup><col width="100%" /></colgroup>
<tbody>
<tr>
<td valign="top" style="line-height: 19.2px">남산원 여름캠프를 시작하였습니다.

<div style="margin: 0px; padding: 0px"><br /></div>
<div style="margin: 0px; padding: 0px">여름 캠프 첫날 오전 영화관에 가서 &lt;엘리멘탈&gt;을 보고</div>
<div style="margin: 0px; padding: 0px"><br /></div>
<div style="margin: 0px; padding: 0px">오후에는 원 내에 설치한 수영장에서 수영을 했습니다.</div>
<div style="margin: 0px; padding: 0px"><br /></div>
<div style="margin: 0px; padding: 0px">남아동/여아동 별로 물놀이하는 동안 노래자랑 프로그램을 진행하여</div>
<div style="margin: 0px; padding: 0px"><br /></div>
<div style="margin: 0px; padding: 0px">&lt;남산가왕&gt;이 선정되었습니다.</div>
<div style="margin: 0px; padding: 0px"><br /></div>
<div style="margin: 0px; padding: 0px">저녁에는 원장님, 국장님이 바베큐를 해주어서 맛있는 식사도 했습니다.</div>
<div style="margin: 0px; padding: 0px"><br /></div></td></tr></tbody>',598,1690988400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (32821,'com3','이재웅','capwoong79@gmail.com','2023년 여름캠프 2일차 (2023.08.02.)','<table border="0" cellspacing="0" cellpadding="0" width="100%" style="font-size: 12px; color: #847f74; line-height: 19.2px; font-family: verdana"><colgroup><col width="100%" /></colgroup>
<tbody>
<tr>
<td valign="top" style="line-height: 19.2px">남산원 여름캠프 2일차

<div style="margin: 0px; padding: 0px"><br /></div>
<div style="margin: 0px; padding: 0px">여름 캠프 2일차에 미취학 아동들은&nbsp;</div>
<div style="margin: 0px; padding: 0px"><br /></div>
