INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (31826,'com3','김형식','','2023 신년 맞이 산행 프로그램','신년을 맞아 아동들과 특별한 프로그램으로 산행을 다녀왔습니다.

<div>원장님께서 산행 리딩을 해주셨는데&nbsp;</div>
<div>남산에 이런 길이 있었나 싶을 정도로&nbsp;</div>
<div>구석구석 걸으며 새로운 길을 알게 되었습니다.</div>
<div><br /></div>
<div>또한 선생님과 아동 1대1로 짝을 지어 산행 프로그램을 진행했는데</div>
<div>1명의 선생님이 1명의 아동에게 온전히 집중할 수 있는 시간이었습니다.</div>
<div>아동들도 짝을 맺은 선생님과 이야기를 나누며 걷는 길이 좋았다고 하네요.</div>
<div><br /></div>
<div>코로나 때문에 진행하지 못했던 프로그램을 다시 시작하니 좋았습니다.</div>
<div>산행 프로그램의 부제 "몸 튼튼! 마음 튼튼!" 처럼</div>
<div>이번 프로그램을 통해 한단계 성장했을 것 같습니다. ^^</div>          </td>
        </tr>',689,1676214000,'', '', '', '', '', '');
