INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28559,'com3','김형식','','해피 할로윈(Happy Halloween)(21.10.29)','<p>요즘 대세는 할로윈데이~~!!</p>
<p>할로윈 데이를 맞아 아동들을 위해 할로윈 축제를 진행했습니다.<br /></p>
<p>아동들 마다 자신의 취향대로&nbsp;한껏 꾸미고, <br /></p>
<p>준비한 호박주머니 안에 사탕과 초콜렛을&nbsp;한아름&nbsp;받아 들었습니다.</p>
<p>한껏 고취된 분위기에 다함께 포즈도 잡고, 간식도 나눠 먹고....</p>
<p>경험하지 못한 새로움이 아동들에게 특별하고 행복한 기억으로 남길 바래봅니다. ^^</p>
<p><br /></p>          </td>
        </tr>',762,1635433200,'', '', '', '', '', '');
