INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28058,'com3','박현정','','2021년 여름캠프 2일차(2021.08.10)','<p>* 2021년 여름캠프 2일차 입니다. </p>
<p>&nbsp; 2일차 여름캠프 프로그램에서는 </p>
<p>&nbsp; 아침조회 원장님 말씀으로 건강하고 즐거운 여름캠프 시작을 알렸습니다.</p>
<p>&nbsp; 오전에는 생활실별 프로그램으로&nbsp;다양한 활동을 하였습니다. 오후에는 물놀이 게임(농구,&nbsp;피구)와&nbsp;</p>
<p>&nbsp; 생활실별 요리활동 프로그램으로 과일, 까나페, 샌드위치, 스파게티, 김밥 등 아동들이 직접 만들어보고</p>
<p>&nbsp; 뷔페식으로 저녁식사가 진행되었습니다. </p>
<p>&nbsp;&nbsp;&nbsp;</p>          </td>
        </tr>',749,1628866800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (28060,'com3','박현정','','2021년 여름캠프 3일차(2021.08.11)','<p>* 3일차 여름캠프 프로그램입니다. </p>
<p>&nbsp; 코로나19로 외부활동이 차단되어 남산원 내에서 여름캠프를 진행하였습니다.</p>
<p>&nbsp; 아쉽게도 영화관 장소 대여가 어려워 \'남산 시네마\' 이름으로 영화관 프로그램이 진행되었습니다.</p>
<p>&nbsp;&nbsp;영화관에서 팝콘과 음료 다양한 간식을 아동들이 직접 구입해보는 매점을 만들어 종이화폐로 구매해보는 기회와 </p>
<p>&nbsp; 기존 공간을 영화관처럼 만들어 새롭고 즐거운 시간이였습니다. </p>
<p>&nbsp;&nbsp;(여름캠프 프로그램에서 아동들의 적극적인 참여를 위해 상점표를 제작하여 참여한 만큼 종이화폐를 제공하였습니다^^)</p>
<p>&nbsp; 오후에는 초등학교 4학년부터 고등학생까지 \'나를 표현해보는 시간\'을 주제로 임상심리상담원 선생님의 </p>
<p>&nbsp;&nbsp;상담 프로그램이 진행되었고, 이후 생활실별로 다양한 만들기 활동, 저녁식사로는 실내에서 외식프로그램이 </p>
<p>&nbsp; 진행되었습니다. 원장님의&nbsp;힘찬 폐회식 선언을 끝으로 아쉽지만 즐거웠던 여름캠프가 마무리 되었습니다.</p>
<p>&nbsp;&nbsp;사고 없이 안전하고 건강하게 캠프를 끝마칠 수 있었습니다. 응원해주신&nbsp;모든 분들께 감사드립니다. &nbsp;</p>          </td>
        </tr>',774,1628866800,'', '', '', '', '', '');
