INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27573,'com3','박현정','','2021년 4월~5월 남산원 베이커리실 공사 완료','<p>* 남산원의 기존 공간을 베이커리실로 새롭게 개보수하는 공사가 마무리되었습니다. </p>
<p>&nbsp; 베이커리실의 제빵기구(반죽기, 오븐기 등)는 서울시중구자원봉사센터 후원을 해주셨습니다^^ </p>
<p>&nbsp;&nbsp;베이커리에 관심이 많은 아동들을 위해 빵을 만들 수 있는 기술을 경험해보고, </p>
<p>&nbsp;&nbsp;베이커리 자격증 등 취업 기술에도 도움이 될 수 있게 지원하고자 합니다. &nbsp;</p>
<p>&nbsp;&nbsp;더욱 더 노력하는 남산원이 되겠습니다. 감사합니다. &nbsp;</p>          </td>
        </tr>',582,1622386800,'', '', '', '', '', '');
