INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (27342,'com3','김형식','','5월5일 어린이날 체육대회 진행했습니다.','<p>제 99회 어린이날을 맞아 남산원 행복운동장에서</p>
<p>어린이날 체육대회를 진행했습니다.</p>
<p>전날 비 바람이 거세 내심 많은 걱정을 했는데</p>
<p>언제 그랬냐는 듯 열린&nbsp;하늘과 따스한 햇볕이</p>
<p>아이들이 맘놓고 체육대회를 즐길 수 있도록 해주었습니다.</p>
<p>남산원의 막내 *현이부터 제일 큰형 *민이까지</p>
<p>운동장이 떠나갈 듯 큰 목소리로 응원하며 하나된 모습이 보기 좋았습니다.&nbsp;</p>
<p>아이들도 재미있는 시간이 되었는지</p>
<p>체육대회를 마치고 뒷정리하는데 연신 재미있었다고 말해주었습니다.</p>
<p>코로나로 인해 답답한 일상을 보내고 있는 아이들에게</p>
<p>신나고 재미있는 시간이 된 것 같습니다.</p>
<p>어서 빨리 마스크 없이 맘껏 어울려 뛰어 놀 수 있는 날이 오면 좋겠네요!!</p>
<p>5월 가정의 달,</p>
<p>남산원 모든 아동들과 원장님을 비롯한 모든 선생님들에게 행복이 가득하면 좋겠습니다 ^^</p>
<p><br /></p>
<p>*코로나19 방역 수칙 준수해 프로그램 진행했습니다.<br /></p>          </td>
        </tr>',715,1620140400,'', '', '', '', '', '');
