INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11223,'com3','박재진','soundpro70@naver.com','9월 27일 전기박사','<div>전기기술자 모임인 전기박사 회원분들께서 남산원을 방문하셔서 창고와 신관&nbsp;배선을 손봐주셨습니다. 지붕에도 올라가시고 혹시나 안전사고는 나지 않을까 걱정했는데 무사히 끝나서 다행입니다. 귀한 손길 감사드리며 다음에 또 뵙겠습니다.</div>
<div>==================== 답 변 ====================</div>
<div>미약한 도움을 드렸다고 생각하였으나 이렇게 큰 도움이라 말씀 주시니 몸둘 바를 모르겠습니다.</div>
<div>&nbsp;</div>
<div>미약한 도움을 지속적으로 드리기 위해 노력하는 전기박사가 되도록 노력하겠습니다. </div>
<div>&nbsp;</div>
<div>전기박사의 일원으로써 오히려 따뜻한 마음이란 무엇인가를 알게 해 주셔서 심심한 감사을 말씀드립니다.</div>          </td>
        </tr>',1341,1411743600,'', '', '', '', '', '');
