INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (10403,'com3','박충일','a7124383@nate.com','6월 4일 남산원아동들 남산올레길 등산','<div>전국동시지방선거일을 맞아 등교하지않는 아동들을 위하여 오랫만에 아빠와 함께 남산올레길을 다녀왔습니다. </div>
<div>이길은 아빠께서 매일 운동하시는 길로 아동들에게 자연을 느끼며 상쾌한 공기를 마시고 건강하게 잘 자라길 바라시는 아빠의 마음이 담긴 남산올레길을 다녀왔습니다. 2시간 코스로 지칠 쯤 아빠께서 편의점에서 음료수 등 간식을 사주셔서 기쁘게 먹고 다시 힘을 내서 잘 다녀왔습니다. 훗날 아동들에게 좋은 추억이 되고 자연을 가까이하는 사람이 되기를 바랍니다. </div>
<div>&nbsp;</div>          </td>
        </tr>',1580,1401807600,'', '', '', '', '', '');
