INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9985,'com3','박충일','a7124383@nate.com','4월 27일 유니클로 후원행사 프로그램','금일 남산원 전 아동이 유니클로 매장에 직접 방문하여 자신의 마음에 드는 옷을 직접 구매하고 계산도 해보는 즐거운 쇼핑 시간을 가졌습니다.  첫 방문부터 큰 박수와 함성으로 맞이해주시고 각 아동 한사람 한사람 1:1 매칭으로 쇼핑을 도와주셔서 알찬 쇼핑을 할 수 있었습니다. 특히 외모에 민감한 청소년아동들이 새 옷을 구입하고 매우 기뻐하였습니다. 오늘 후원행사를 베풀어주신 유니클로 임직원여러분들께 진심으로 감사드립니다.^^*          </td>
