INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (9840,'com3','김혜진','emo82@naver.com','이진경 후원회장님과 룻2방 *민,**영,*연이의 외출  (2013.03.07)','오늘 남산원에 이진경후원회장님께서 방문하셔서 영아방 선물을 사러
룻2방 *민,*영,*연이와 함께 외출을 다녀오셨습니다.
아이들이 학교에서 돌아오자마자 밝은 미소로 아이들을 반겨주시는
후원회장님과 함께하는 시간이 즐거운 아이들입니다.
항상 아이들과 함께해주시고 남산원을 생각해주시는 소중한 마음
정말 감사드립니다~!^.^          </td>
